    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 10–12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Garlic, Ginger, Onion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream, add chicken, simmer 10 min.\n6. Serve over basmati rice.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheese, Sour cream, Salsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onions, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Stir-fry shrimp until pink, set aside.\n3. Scramble eggs in the wok.\n4. Add drained noodles with tamarind, fish sauce, and sugar.\n5. Toss in shrimp, bean sprouts, and green onions.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture quickly.\n6. Serve immediately with extra pecorino.", AverageRating = 4.7, RatingCount = 18 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Red onion, Cilantro, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados, scoop into bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, jalapeño, tomato, and cilantro.\n4. Add lime juice and salt to taste.\n5. Serve immediately with tortilla chips.", AverageRating = 4.4, RatingCount = 10 },
        new Recipe { Id = 7, Title = "Green Curry", Category = "Thai", Ingredients = "Green curry paste, Coconut milk, Chicken breast, Bamboo shoots, Thai basil, Fish sauce, Sugar, Thai eggplant", Steps = "1. Heat coconut cream in a wok until oil separates.\n2. Fry curry paste until fragrant.\n3. Add sliced chicken, cook through.\n4. Pour in coconut milk, add bamboo shoots and eggplant.\n5. Season with fish sauce and sugar.\n6. Stir in Thai basil, serve over jasmine rice.", AverageRating = 4.3, RatingCount = 9 },
        new Recipe { Id = 8, Title = "Butter Chicken", Category = "Indian", Ingredients = "Chicken thighs, Butter, Tomato puree, Cream, Garam masala, Fenugreek leaves, Garlic, Ginger, Chili powder", Steps = "1. Marinate chicken in yogurt and spices, grill until done.\n2. Melt butter, sauté garlic and ginger.\n3. Add tomato puree, simmer 20 min.\n4. Stir in cream, garam masala, and fenugreek.\n5. Add grilled chicken pieces, simmer 10 min.\n6. Serve with naan bread.", AverageRating = 4.9, RatingCount = 25 },
    };

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _recipes.Max(r => r.Id) + 1,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
        };
        _recipes.Add(recipe);
    }

    public void RateRecipe(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = (totalStars + stars) / recipe.RatingCount;
    }
}

