﻿@page "/"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>RecipeHub — Home</PageTitle>

<h1>🍳 Welcome to RecipeHub</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-3 mb-4">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                    <p class="card-text text-muted">
                        @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                    </p>
                    <a href="/category/@category" class="btn btn-outline-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Mexican" => "🇲🇽",
        "Thai" => "🇹🇭",
        _ => "🍽️"
    };
}

