+    [Parameter] public int RecipeId { get; set; }
+    [Parameter] public double CurrentRating { get; set; }
+    [Parameter] public int RatingCount { get; set; }
+
+    private int hoverStar;
+    private bool submitted;
+    private int submittedRating;
+
+    private bool IsStarFilled(int star)
+    {
+        if (hoverStar > 0) return star <= hoverStar;
+        return star <= (int)Math.Round(CurrentRating);
+    }
+
+    private string GetStarClass(int star) =>
+        IsStarFilled(star) ? "text-warning" : "text-muted";
+
+    private void Rate(int stars)
+    {
+        RecipeService.RateRecipe(RecipeId, stars);
+        var recipe = RecipeService.GetRecipeById(RecipeId);
+        if (recipe is not null)
+        {
+            CurrentRating = recipe.AverageRating;
+            RatingCount = recipe.RatingCount;
+        }
+        submitted = true;
+        submittedRating = stars;
+    }
+}
+

toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
        <ValidationMessage For="() => submission.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => submission.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients</label>
        <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="5"
                       placeholder="One ingredient per line or comma-separated" />
        <ValidationMessage For="() => submission.Ingredients" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps</label>
        <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6"
                       placeholder="Describe each step..." />
        <ValidationMessage For="() => submission.Steps" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private RecipeSubmission submission = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(submission);
        successMessage = $"'{submission.Title}' submitted successfully!";
        submission = new();
    }
}

